import java.util.*;

class ValidWordAbbr {
    private Map<String, Set<String>> wordMap;

    public ValidWordAbbr(String[] dictionary) {
        wordMap = new HashMap<>();
        for (String word : dictionary) {
            String abbr = getAbbreviation(word);
            wordMap.putIfAbsent(abbr, new HashSet<>());
            wordMap.get(abbr).add(word);
        }
    }

    public boolean isUnique(String word) {
        String abbr = getAbbreviation(word);
        Set<String> abbrGroup = wordMap.get(abbr);
        return abbrGroup == null || (abbrGroup.size() == 1 && abbrGroup.contains(word));
    }

    private String getAbbreviation(String word) {
        int n = word.length();
        return n <= 2 ? word : word.charAt(0) + Integer.toString(n - 2) + word.charAt(n - 1);
    }
}
